{
  "test_file": "// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "forge-std/Test.sol";
import "../src/Vault.sol";
import "../src/ERC20.sol";

contract TestVault is Test {
    Vault vault;
    ERC20 token;
    address owner = address(1);
    address depositor = address(2);
    address depositor2 = address(3);
    address attacker = address(4);
    address newOwner = address(5);

    function setUp() public {
        vm.startPrank(owner);
        token = new ERC20("Test Token", "TT", 18);
        vault = new Vault(address(token));
        token.mint(depositor, 1e27);
        token.mint(depositor2, 1e27);
        token.mint(attacker, 1e27);

        vault.whitelistDepositor(depositor, true);
        vault.whitelistDepositor(depositor2, true);

        vm.stopPrank();

        vm.prank(depositor);
        token.approve(address(vault), type(uint256).max);
        vm.prank(depositor2);
        token.approve(address(vault), type(uint256).max);
    }

    // Edge cases from edge_case_hunter

    function test_RevertWhen_depositMaxAmountOverflow() public {
        vault.deposit(100);
        vm.expectRevert(stdError.arithmeticError);
        vault.deposit(type(uint256).max);
    }

    function test_RevertWhen_withdrawMaxSharesOverflow() public {
        vault.deposit(100);
        vm.expectRevert(stdError.arithmeticError);
        vault.withdraw(type(uint256).max);
    }

    function test_whitelistZeroAddress() public {
        vm.prank(owner);
        vault.whitelistDepositor(address(0), true);
        assertTrue(vault.allowedDepositors(address(0)));
    }

    function test_emergencyWithdrawToZero() public {
        vault.deposit(1000);
        vm.prank(owner);
        vault.emergencyWithdraw(address(0), 1000);
        assertEq(token.balanceOf(address(0)), 1000);
    }

    // Coverage tests from coverage_analyzer

    function test_RevertWhen_ZeroAssetConstructor() public {
        vm.expectRevert(Vault.ZeroAmount.selector);
        new Vault(address(0));
    }

    function test_ValidAssetConstructor() public {
        Vault v = new Vault(address(token));
        assertEq(address(v.asset()), address(token));
        assertEq(v.owner(), address(this));
    }

    function test_RevertWhen_NonOwnerSetsPaused() public {
        vm.prank(attacker);
        vm.expectRevert(Vault.NotOwner.selector);
        vault.setPaused(true);
    }

    function test_OwnerSetsPaused() public {
        vm.prank(owner);
        vault.setPaused(true);
        assertTrue(vault.paused());
    }

    function test_RevertWhen_DepositWhilePaused() public {
        vm.prank(owner);
        vault.setPaused(true);
        vm.prank(depositor);
        vm.expectRevert(Vault.VaultPaused.selector);
        vault.deposit(1000);
    }

    function test_DepositWhenNotPaused() public {
        vm.prank(depositor);
        vault.deposit(1000);
        assertEq(vault.totalAssets(), 1000);
    }

    function test_RevertWhen_NonWhitelistedDeposits() public {
        vm.prank(attacker);
        vm.expectRevert(Vault.NotWhitelisted.selector);
        vault.deposit(1000);
    }

    function test_WhitelistedUserDeposits() public {
        vm.prank(depositor);
        vault.deposit(1000);
        assertGt(vault.shareBalance(depositor), 0);
    }

    function test_RevertWhen_DepositZeroAmount() public {
        vm.prank(depositor);
        vm.expectRevert(Vault.ZeroAmount.selector);
        vault.deposit(0);
    }

    function test_FirstDepositUsesAmountAsShares() public {
        vm.prank(depositor);
        vault.deposit(1000);
        assertEq(vault.shareBalance(depositor), 1000);
        assertEq(vault.totalShares(), 1000);
        assertEq(vault.totalAssets(), 1000);
    }

    function test_SubsequentDepositCalculatesShares() public {
        vm.prank(depositor);
        vault.deposit(1000);
        vm.prank(depositor2);
        vault.deposit(2000);
        uint256 expectedShares = (2000 * 1000) / 1000;
        assertEq(vault.shareBalance(depositor2), expectedShares);
    }

    function test_RevertWhen_WithdrawZeroShares() public {
        vm.prank(depositor);
        vm.expectRevert(Vault.ZeroAmount.selector);
        vault.withdraw(0);
    }

    function test_RevertWhen_InsufficientShares() public {
        vm.prank(depositor);
        vault.deposit(1000);
        vm.expectRevert(Vault.InsufficientShares.selector);
        vault.withdraw(2000);
    }

    function test_RevertWhen_LockNotElapsed() public {
        vm.prank(depositor);
        vault.deposit(1000);
        vm.expectRevert(Vault.LockNotElapsed.selector);
        vm.prank(depositor);
        vault.withdraw(1000);
    }

    function test_WithdrawAfterLockElapses() public {
        vm.prank(depositor);
        vault.deposit(1000);
        vm.warp(block.timestamp + 7 days + 1);
        uint256 balBefore = token.balanceOf(depositor);
        vm.prank(depositor);
        vault.withdraw(1000);
        assertGt(token.balanceOf(depositor), balBefore);
        assertEq(vault.shareBalance(depositor), 0);
    }

    function test_WithdrawWithFeeTransferredToOwner() public {
        vm.prank(depositor);
        vault.deposit(10000);
        vm.warp(block.timestamp + 7 days + 1);
        uint256 ownerBalBefore = token.balanceOf(owner);
        vm.prank(depositor);
        vault.withdraw(10000);
        assertGt(token.balanceOf(owner), ownerBalBefore);
    }

    function test_RevertWhen_FeeTooHigh() public {
        vm.prank(owner);
        vm.expectRevert(Vault.FeeTooHigh.selector);
        vault.setWithdrawFee(1001);
    }

    function test_SetWithdrawFeeValid() public {
        vm.prank(owner);
        vault.setWithdrawFee(500);
        assertEq(vault.withdrawFeeBps(), 500);
    }

    function test_RevertWhen_TransferOwnershipToZero() public {
        vm.prank(owner);
        vm.expectRevert(Vault.ZeroAmount.selector);
        vault.transferOwnership(address(0));
    }

    function test_TransferOwnershipValid() public {
        vm.prank(owner);
        vault.transferOwnership(newOwner);
        assertEq(vault.owner(), newOwner);
    }

    function test_PricePerShareWhenNoDeposits() public view {
        assertEq(vault.pricePerShare(), 1e18);
    }

    function test_PricePerShareWithDeposits() public {
        vm.prank(depositor);
        vault.deposit(2000);
        uint256 pps = vault.pricePerShare();
        assertEq(pps, 1e18);
    }

    // Note: Additional tests for uncovered branches (ERC20 return false) would require mock tokens
}",
